 1→{
 2→  "name": "founder-os",
 3→  "version": "1.0.0",
 4→  "description": "32-plugin AI automation ecosystem for SMB founders. Email triage, meeting prep, report generation, CRM sync, and 28 more tools — all powered by Claude Code.",
 5→  "author": {
 6→    "name": "Founder OS",
 7→    "email": "contact@founderos.dev"
 8→  }
 9→}
10→

  1→#!/usr/bin/env node
  2→import { Client } from "@notionhq/client";
  3→import { readFileSync } from "node:fs";
  4→import { dirname, resolve } from "node:path";
  5→import { fileURLToPath } from "node:url";
  6→
  7→// ── Arg parsing helpers ──────────────────────────────────────────────
  8→const argv = process.argv.slice(2);
  9→
 10→function flag(name) {
 11→  const i = argv.indexOf(`--${name}`);
 12→  if (i === -1) return undefined;
 13→  const val = argv[i + 1];
 14→  return val && !val.startsWith("--") ? val : true;
 15→}
 16→
 17→function hasFlag(name) {
 18→  return argv.includes(`--${name}`);
 19→}
 20→
 21→function jsonFlag(name) {
 22→  const v = flag(name);
 23→  if (v === undefined || v === true) return undefined;
 24→  try { return JSON.parse(v); } catch { errExit(`Invalid JSON for --${name}`, "NOTION_VALIDATION", `Ensure --${name} is valid JSON`); }
 25→}
 26→
 27→// ── Output helpers ───────────────────────────────────────────────────
 28→function ok(data) { process.stdout.write(JSON.stringify(data, null, 2) + "\n"); process.exit(0); }
 29→function errExit(error, code, hint) {
 30→  process.stderr.write(JSON.stringify({ error, code, hint }) + "\n");
 31→  process.exit(1);
 32→}
 33→
 34→// ── Auth resolution ──────────────────────────────────────────────────
 35→function resolveAuth() {
 36→  if (process.env.NOTION_API_KEY) return process.env.NOTION_API_KEY;
 37→  // Walk up from script dir looking for .env
 38→  const __dirname = dirname(fileURLToPath(import.meta.url));
 39→  let dir = __dirname;
 40→  for (let i = 0; i < 5; i++) {
 41→    try {
 42→      const env = readFileSync(resolve(dir, ".env"), "utf8");
 43→      const m = env.match(/^NOTION_API_KEY=(.+)$/m);
 44→      if (m) return m[1].trim();
 45→    } catch { /* not found, walk up */ }
 46→    dir = dirname(dir);
 47→  }
 48→  errExit("No Notion API key found", "NOTION_AUTH_MISSING", "Run /founder-os:setup:notion-cli to configure");
 49→}
 50→
 51→// ── Notion URL → UUID ────────────────────────────────────────────────
 52→function extractId(input) {
 53→  const hex = input.replace(/-/g, "").match(/([0-9a-f]{32})(?:[?#]|$)/i);
 54→  if (hex) {
 55→    const h = hex[1];
 56→    return `${h.slice(0,8)}-${h.slice(8,12)}-${h.slice(12,16)}-${h.slice(16,20)}-${h.slice(20)}`;
 57→  }
 58→  // Already a UUID or bare ID
 59→  if (/^[0-9a-f-]{32,36}$/i.test(input)) {
 60→    const bare = input.replace(/-/g, "");
 61→    return `${bare.slice(0,8)}-${bare.slice(8,12)}-${bare.slice(12,16)}-${bare.slice(16,20)}-${bare.slice(20)}`;
 62→  }
 63→  return input;
 64→}
 65→
 66→// ── Auto-pagination ──────────────────────────────────────────────────
 67→async function paginate(fn) {
 68→  let cursor = undefined;
 69→  const all = [];
 70→  do {
 71→    const res = await fn(cursor);
 72→    all.push(...res.results);
 73→    cursor = res.has_more ? res.next_cursor : undefined;
 74→  } while (cursor);
 75→  return all;
 76→}
 77→
 78→// ── Retry with backoff (for 429) ─────────────────────────────────────
 79→async function withRetry(fn, retries = 3) {
 80→  for (let i = 0; i <= retries; i++) {
 81→    try { return await fn(); } catch (e) {
 82→      if (e.status === 429 && i < retries) {
 83→        await new Promise(r => setTimeout(r, 1000 * Math.pow(2, i)));
 84→        continue;
 85→      }
 86→      throw e;
 87→    }
 88→  }
 89→}
 90→
 91→// ── Error wrapper ────────────────────────────────────────────────────
 92→async function run(fn) {
 93→  try { await fn(); } catch (e) {
 94→    if (e.status === 401) errExit(e.message || "Unauthorized", "NOTION_AUTH_FAILED", "Run /founder-os:setup:notion-cli");
 95→    if (e.status === 404) errExit(e.message || "Not found", "NOTION_NOT_FOUND", "Check sharing permissions");
 96→    if (e.status === 429) errExit(e.message || "Rate limited", "NOTION_RATE_LIMIT", "Too many requests — try again later");
 97→    if (e.code === "ECONNABORTED" || e.code === "ETIMEDOUT" || e.name === "AbortError")
 98→      errExit("Request timed out", "NOTION_TIMEOUT", "Network issue — try again");
 99→    if (e.status === 400) errExit(e.message || "Validation error", "NOTION_VALIDATION", e.body || "Check parameters");
100→    errExit(e.message || String(e), "NOTION_ERROR", "Unexpected error");
101→  }
102→}
103→
104→// ── Help text ────────────────────────────────────────────────────────
105→const HELP = `notion-tool.mjs — Notion CLI wrapper for Founder OS
106→
107→Usage: node notion-tool.mjs <command> [args] [options]
108→
109→Commands:
110→  search <query>                Search pages & databases (--filter page|database)
111→  query <database-id>           Query a database (--filter json, --sorts json, --page-size N)
112→  create-page <parent-id>       Create a page (--properties json, --content json)
113→  update-page <page-id>         Update page properties (--properties json)
114→  get-page <page-id-or-url>     Retrieve a page
115→  get-blocks <page-id>          List child blocks (--recursive)
116→  get-comments <page-id>        List comments on a page
117→  create-comment <page-id>      Add a comment (--body text)
118→  create-database <parent-id>   Create a database (--title text, --properties json)
119→  update-database <database-id> Update database properties (--properties json)
120→  fetch <notion-url>            Auto-detect & retrieve page/database/block
121→
122→Flags:
123→  --diagnostic   Run diagnostics (auth check, DB list, read/write test)
124→  --help         Show this help text
125→
126→Environment:
127→  NOTION_API_KEY   Notion integration token (or set in .env file)
128→`;
129→
130→// ── Main ─────────────────────────────────────────────────────────────
131→const cmd = argv[0];
132→
133→if (!cmd || hasFlag("help")) { process.stdout.write(HELP); process.exit(0); }
134→
135→// Diagnostic mode
136→if (hasFlag("diagnostic")) {
137→  const key = resolveAuth();
138→  const notion = new Client({ auth: key, timeoutMs: 10000 });
139→  const report = { auth: null, databases: null, readWriteTest: null, latency: {} };
140→
141→  await run(async () => {
142→    let t = Date.now();
143→    const me = await notion.users.me({});
144→    report.latency.auth = Date.now() - t;
145→    report.auth = { ok: true, user: me.name, type: me.type };
146→
147→    t = Date.now();
148→    const dbs = await notion.search({ filter: { value: "database", property: "object" }, page_size: 50 });
149→    report.latency.listDatabases = Date.now() - t;
150→    report.databases = { count: dbs.results.length, names: dbs.results.map(d => d.title?.[0]?.plain_text || "(untitled)") };
151→
152→    // Read/write test: create temp page in first DB, read, archive
153→    if (dbs.results.length > 0) {
154→      const dbId = dbs.results[0].id;
155→      t = Date.now();
156→      const page = await notion.pages.create({
157→        parent: { database_id: dbId },
158→        properties: { title: { title: [{ text: { content: "[FOS] diagnostic test — safe to delete" } }] } },
159→      });
160→      report.latency.createPage = Date.now() - t;
161→
162→      t = Date.now();
163→      await notion.pages.retrieve({ page_id: page.id });
164→      report.latency.readPage = Date.now() - t;
165→
166→      t = Date.now();
167→      await notion.pages.update({ page_id: page.id, archived: true });
168→      report.latency.archivePage = Date.now() - t;
169→      report.readWriteTest = { ok: true, pageId: page.id };
170→    } else {
171→      report.readWriteTest = { ok: false, reason: "No databases accessible — cannot test read/write" };
172→    }
173→    ok(report);
174→  });
175→  process.exit(0);
176→}
177→
178→// All other commands require auth
179→const key = resolveAuth();
180→const notion = new Client({ auth: key, timeoutMs: 10000 });
181→const positional = argv.filter(a => !a.startsWith("--")).slice(1);
182→
183→await run(async () => {
184→  switch (cmd) {
185→    case "search": {
186→      const query = positional[0] || "";
187→      const filterVal = flag("filter");
188→      const params = { query, page_size: 100 };
189→      if (filterVal === "page" || filterVal === "database")
190→        params.filter = { value: filterVal, property: "object" };
191→      const results = await withRetry(() => paginate(cursor => notion.search({ ...params, start_cursor: cursor })));
192→      ok(results);
193→      break;
194→    }
195→    case "query": {
196→      const dbId = extractId(positional[0] || errExit("database-id required", "NOTION_VALIDATION", "Provide a database ID"));
197→      const params = { database_id: dbId, page_size: Number(flag("page-size")) || 100 };
198→      const f = jsonFlag("filter"); if (f) params.filter = f;
199→      const s = jsonFlag("sorts"); if (s) params.sorts = s;
200→      const results = await withRetry(() => paginate(cursor => notion.databases.query({ ...params, start_cursor: cursor })));
201→      ok(results);
202→      break;
203→    }
204→    case "create-page": {
205→      const parentId = extractId(positional[0] || errExit("parent-id required", "NOTION_VALIDATION", "Provide a parent database ID"));
206→      const props = jsonFlag("properties") || {};
207→      const content = jsonFlag("content");
208→      const params = { parent: { database_id: parentId }, properties: props };
209→      if (content) params.children = content;
210→      const page = await withRetry(() => notion.pages.create(params));
211→      ok(page);
212→      break;
213→    }
214→    case "update-page": {
215→      const pageId = extractId(positional[0] || errExit("page-id required", "NOTION_VALIDATION", "Provide a page ID"));
216→      const props = jsonFlag("properties") || errExit("--properties required", "NOTION_VALIDATION", "Provide --properties JSON");
217→      const page = await withRetry(() => notion.pages.update({ page_id: pageId, properties: props }));
218→      ok(page);
219→      break;
220→    }
221→    case "get-page": {
222→      const pageId = extractId(positional[0] || errExit("page-id required", "NOTION_VALIDATION", "Provide a page ID or URL"));
223→      const page = await withRetry(() => notion.pages.retrieve({ page_id: pageId }));
224→      ok(page);
225→      break;
226→    }
227→    case "get-blocks": {
228→      const blockId = extractId(positional[0] || errExit("page-id required", "NOTION_VALIDATION", "Provide a page/block ID"));
229→      const recursive = hasFlag("recursive");
230→      const blocks = await withRetry(() => paginate(cursor => notion.blocks.children.list({ block_id: blockId, start_cursor: cursor, page_size: 100 })));
231→      if (recursive) {
232→        for (const block of blocks) {
233→          if (block.has_children) {
234→            block.children = await withRetry(() => paginate(cursor => notion.blocks.children.list({ block_id: block.id, start_cursor: cursor, page_size: 100 })));
235→          }
236→        }
237→      }
238→      ok(blocks);
239→      break;
240→    }
241→    case "get-comments": {
242→      const blockId = extractId(positional[0] || errExit("page-id required", "NOTION_VALIDATION", "Provide a page ID"));
243→      const comments = await withRetry(() => paginate(cursor => notion.comments.list({ block_id: blockId, start_cursor: cursor })));
244→      ok(comments);
245→      break;
246→    }
247→    case "create-comment": {
248→      const pageId = extractId(positional[0] || errExit("page-id required", "NOTION_VALIDATION", "Provide a page ID"));
249→      const body = flag("body") || errExit("--body required", "NOTION_VALIDATION", "Provide --body text");
250→      const comment = await withRetry(() => notion.comments.create({
251→        parent: { page_id: pageId },
252→        rich_text: [{ text: { content: body } }],
253→      }));
254→      ok(comment);
255→      break;
256→    }
257→    case "create-database": {
258→      const parentId = extractId(positional[0] || errExit("parent-id required", "NOTION_VALIDATION", "Provide a parent page ID"));
259→      const title = flag("title") || "Untitled";
260→      const props = jsonFlag("properties") || {};
261→      const db = await withRetry(() => notion.databases.create({
262→        parent: { page_id: parentId },
263→        title: [{ text: { content: title } }],
264→        properties: props,
265→      }));
266→      ok(db);
267→      break;
268→    }
269→    case "update-database": {
270→      const dbId = extractId(positional[0] || errExit("database-id required", "NOTION_VALIDATION", "Provide a database ID"));
271→      const props = jsonFlag("properties") || errExit("--properties required", "NOTION_VALIDATION", "Provide --properties JSON");
272→      const db = await withRetry(() => notion.databases.update({ database_id: dbId, properties: props }));
273→      ok(db);
274→      break;
275→    }
276→    case "fetch": {
277→      const url = positional[0] || errExit("notion-url required", "NOTION_VALIDATION", "Provide a Notion URL");
278→      const id = extractId(url);
279→      // Try page, then database, then block
280→      for (const tryFn of [
281→        () => notion.pages.retrieve({ page_id: id }),
282→        () => notion.databases.retrieve({ database_id: id }),
283→        () => notion.blocks.retrieve({ block_id: id }),
284→      ]) {
285→        try { const res = await withRetry(tryFn); ok(res); } catch { continue; }
286→      }
287→      errExit(`Could not resolve: ${url}`, "NOTION_NOT_FOUND", "Check the URL and sharing permissions");
288→      break;
289→    }
290→    default:
291→      errExit(`Unknown command: ${cmd}`, "NOTION_VALIDATION", "Run with --help to see available commands");
292→  }
293→});
294→

